from flask import Flask, request, jsonify, send_file, abort
import os

app = Flask(__name__)
USER_ROOT = '/path/to/user/root'  # Change this to the actual user root directory

def safe_join(base, path):
    normalized_path = os.path.normpath(path)
    full_path = os.path.join(base, normalized_path)
    if not full_path.startswith(os.path.abspath(base)):
        abort(403)  # Forbidden access
    return full_path

@app.route('/list', methods=['GET'])
def list_directory():
    relative_path = request.args.get('path', '')
    full_path = safe_join(USER_ROOT, relative_path)
    
    if not os.path.isdir(full_path):
        abort(404)  # Not found
    
    files = os.listdir(full_path)
    return jsonify(files)

@app.route('/download', methods=['GET'])
def download_file():
    relative_path = request.args.get('path', '')
    full_path = safe_join(USER_ROOT, relative_path)
    
    if not os.path.isfile(full_path):
        abort(404)  # Not found
    
    return send_file(full_path)

@app.route('/info', methods=['GET'])
def get_file_info():
    relative_path = request.args.get('path', '')
    full_path = safe_join(USER_ROOT, relative_path)
    
    if not os.path.exists(full_path):
        abort(404)  # Not found
    
    file_info = {
        'size': os.path.getsize(full_path),
        'modified_time': os.path.getmtime(full_path),
        'is_directory': os.path.isdir(full_path)
    }
    return jsonify(file_info)

if __name__ == '__main__':
    app.run(debug=True)